/**
 * @summary List chat messages for an event
 */
export const getListChatMessagesUrl = (
  eventId: number,
  params?: ListChatMessagesParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/events/${eventId}/chat?${stringifiedParams}`
    : `/api/events/${eventId}/chat`;
};

export const listChatMessages = async (
  eventId: number,
  params?: ListChatMessagesParams,
  options?: RequestInit,
): Promise<ChatMessageListResponse> => {
  return customFetch<ChatMessageListResponse>(
    getListChatMessagesUrl(eventId, params),
    {
      ...options,
      method: "GET",
    },
  );
};

